function Contact() {
    return (
        <section className="container py-5 text-center">
            <h2 className="mb-4">Contáctame</h2>
            <p className="mb-4">¿Trabajamos juntos? Escríbeme y conversemos sobre tu proyecto.</p>
            <a href="https://wa.link/y8lwlm" target="_blank" rel="noopener noreferrer" className="btn btn-success btn-lg">
                <i className="bi bi-whatsapp me-2"></i>Contactar por WhatsApp
            </a>
        </section>
    );
}

export default Contact;
